@Test fun retriesAfterDelay() = runTest {
    val job = launch { delay(5_000); repository.retry() }
    runCurrent()
    assertFalse(job.isCompleted)
    advanceTimeBy(5_000)
    runCurrent()
    assertTrue(job.isCompleted)
}

class UserRepository(private val io: CoroutineDispatcher) {
    suspend fun load() = withContext(io) { api.load() }
}

@Test fun loadUsesControlledScheduler() = runTest {
    val dispatcher = StandardTestDispatcher(testScheduler)
    val repository = UserRepository(dispatcher)
    val deferred = async { repository.load() }
    runCurrent()
    assertEquals(expected, deferred.await())
}

class MainDispatcherRule(
    val dispatcher: TestDispatcher = StandardTestDispatcher()
) : TestWatcher() {
    override fun starting(d: Description) = Dispatchers.setMain(dispatcher)
    override fun finished(d: Description) = Dispatchers.resetMain()
}
